import{_ as e,o,c as a,ae as r}from"./chunks/framework.BD9pLfSD.js";const u=JSON.parse('{"title":"🦅 xB77: MASTER PLAN & STRATEGY","description":"","frontmatter":{},"headers":[],"relativePath":"docs/plans/MASTER_PLAN.md","filePath":"docs/plans/MASTER_PLAN.md"}'),n={name:"docs/plans/MASTER_PLAN.md"};function i(s,t,l,d,h,c){return o(),a("div",null,[...t[0]||(t[0]=[r('<h1 id="🦅-xb77-master-plan-strategy" tabindex="-1">🦅 xB77: MASTER PLAN &amp; STRATEGY <a class="header-anchor" href="#🦅-xb77-master-plan-strategy" aria-label="Permalink to &quot;🦅 xB77: MASTER PLAN &amp; STRATEGY&quot;">​</a></h1><blockquote><p><strong>Target:</strong> Solana Privacy Hackathon (Deadline: Feb 1, 2026) <strong>Mission:</strong> &quot;The Operating System for the Shadow Economy of AI Agents.&quot; <strong>Current Date:</strong> Jan 20, 2026. <strong>Days Remaining:</strong> 12.</p></blockquote><hr><h2 id="️-the-map-architecture" tabindex="-1">️ THE MAP (Architecture) <a class="header-anchor" href="#️-the-map-architecture" aria-label="Permalink to &quot;️ THE MAP (Architecture)&quot;">​</a></h2><p>We are building a &quot;Privacy Triad&quot; to solve the Agent Economy&#39;s exposure problem.</p><h3 id="_1-the-vault-worktree-a-privacy-cash" tabindex="-1">1. THE VAULT (Worktree A - &quot;Privacy Cash&quot;) <a class="header-anchor" href="#_1-the-vault-worktree-a-privacy-cash" aria-label="Permalink to &quot;1. THE VAULT (Worktree A - &quot;Privacy Cash&quot;)&quot;">​</a></h3><ul><li><strong>Role:</strong> Holds the money (Confidential Treasury).</li><li><strong>Tech:</strong> <strong>Arcium C-SPL</strong> (Confidential Token Standard).</li><li><strong>Asset:</strong> <strong>USD1</strong> (Privacy Cash) or USDC-Confidential.</li><li><strong>Key Feature:</strong> &quot;Shadow Balance&quot;. The CFO sees $1M, the public sees <code>encrypted_blob</code>.</li></ul><h3 id="_2-the-black-box-worktree-b-light-protocol" tabindex="-1">2. THE BLACK BOX (Worktree B - &quot;Light Protocol&quot;) <a class="header-anchor" href="#_2-the-black-box-worktree-b-light-protocol" aria-label="Permalink to &quot;2. THE BLACK BOX (Worktree B - &quot;Light Protocol&quot;)&quot;">​</a></h3><ul><li><strong>Role:</strong> Holds the history (Audit Trail).</li><li><strong>Tech:</strong> <strong>Light Protocol (ZK Compression)</strong>.</li><li><strong>Asset:</strong> <strong>Compressed PDAs</strong> (Receipts).</li><li><strong>Key Feature:</strong> &quot;Ghost Receipts&quot;. Every spend creates a permanent, compressed, encrypted record of <em>what</em> was bought, without leaking it on-chain.</li></ul><h3 id="_3-the-ghost-badge-root-identity" tabindex="-1">3. THE GHOST BADGE (Root - &quot;Identity&quot;) <a class="header-anchor" href="#_3-the-ghost-badge-root-identity" aria-label="Permalink to &quot;3. THE GHOST BADGE (Root - &quot;Identity&quot;)&quot;">​</a></h3><ul><li><strong>Role:</strong> Authorizes the spender.</li><li><strong>Tech:</strong> <strong>Noir (Aztec)</strong> on Solana.</li><li><strong>Key Feature:</strong> &quot;Proof of Authority&quot;. An agent proves it belongs to the Company Merkle Tree without revealing <em>which</em> agent it is.</li></ul><hr><h2 id="-execution-strategy-divide-conquer" tabindex="-1"> EXECUTION STRATEGY (Divide &amp; Conquer) <a class="header-anchor" href="#-execution-strategy-divide-conquer" aria-label="Permalink to &quot; EXECUTION STRATEGY (Divide &amp; Conquer)&quot;">​</a></h2><p>We are splitting the codebase into focused Worktrees to bypass infrastructure blockers.</p><table tabindex="0"><thead><tr><th style="text-align:left;">Component</th><th style="text-align:left;">Owner</th><th style="text-align:left;">Status</th><th style="text-align:left;">Blocker</th><th style="text-align:left;">Strategy</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Root (Noir)</strong></td><td style="text-align:left;">Main</td><td style="text-align:left;">🟢 Ready</td><td style="text-align:left;">None</td><td style="text-align:left;">Compile Circuits &amp; Generate Verifier.</td></tr><tr><td style="text-align:left;"><strong>Worktree A</strong></td><td style="text-align:left;">Privacy</td><td style="text-align:left;">🟡 Pending</td><td style="text-align:left;">Arcium Localnet</td><td style="text-align:left;"><strong>Use Devnet directly.</strong> Skip local docker if unstable.</td></tr><tr><td style="text-align:left;"><strong>Worktree B</strong></td><td style="text-align:left;">Light</td><td style="text-align:left;"> Blocked</td><td style="text-align:left;">Local Validator</td><td style="text-align:left;"><strong>Switch to Devnet / Mocking.</strong> Develop contracts against mocked interfaces first.</td></tr></tbody></table><hr><h2 id="-the-10-day-sprint" tabindex="-1"> THE 10-DAY SPRINT <a class="header-anchor" href="#-the-10-day-sprint" aria-label="Permalink to &quot; THE 10-DAY SPRINT&quot;">​</a></h2><h3 id="days-1-3-the-foundation-jan-20-jan-22" tabindex="-1">Days 1-3: The Foundation (Jan 20 - Jan 22) <a class="header-anchor" href="#days-1-3-the-foundation-jan-20-jan-22" aria-label="Permalink to &quot;Days 1-3: The Foundation (Jan 20 - Jan 22)&quot;">​</a></h3><ul><li><strong>Root:</strong> Finalize <code>agent_badge</code> circuit (Noir) and generate Solidity/Solana verifier.</li><li><strong>Tree A:</strong> Deploy a basic C-SPL token on Arcium Devnet. Mint &quot;Shadow USD&quot;.</li><li><strong>Tree B:</strong> Finish <code>xb77_gateway</code> logic (Rust). Implement the &quot;Receipt&quot; struct in Light SDK. <strong>Ignore local validator issues; use Devnet for deployment.</strong></li></ul><h3 id="days-4-6-the-integration-jan-23-jan-25" tabindex="-1">Days 4-6: The Integration (Jan 23 - Jan 25) <a class="header-anchor" href="#days-4-6-the-integration-jan-23-jan-25" aria-label="Permalink to &quot;Days 4-6: The Integration (Jan 23 - Jan 25)&quot;">​</a></h3><ul><li><strong>Gateway:</strong> Connect Noir Verifier -&gt; Arcium Transfer.</li><li><strong>Receipts:</strong> Gateway -&gt; emits Compressed Receipt (Light).</li><li><strong>SDK:</strong> Create <code>@xb77/sdk</code> to abstract all this complexity for the frontend.</li></ul><h3 id="days-7-9-the-interface-jan-26-jan-28" tabindex="-1">Days 7-9: The Interface (Jan 26 - Jan 28) <a class="header-anchor" href="#days-7-9-the-interface-jan-26-jan-28" aria-label="Permalink to &quot;Days 7-9: The Interface (Jan 26 - Jan 28)&quot;">​</a></h3><ul><li><strong>UI:</strong> Build the &quot;Shadow Console&quot; (Terminal style). <ul><li>View 1: <strong>CFO Mode</strong> (Decrypts everything).</li><li>View 2: <strong>Auditor Mode</strong> (Verifies proofs).</li></ul></li><li><strong>Agent:</strong> Create a simple CLI agent that &quot;buys&quot; an API key using the system.</li></ul><h3 id="days-10-12-polish-demo-jan-29-feb-1" tabindex="-1">Days 10-12: Polish &amp; Demo (Jan 29 - Feb 1) <a class="header-anchor" href="#days-10-12-polish-demo-jan-29-feb-1" aria-label="Permalink to &quot;Days 10-12: Polish &amp; Demo (Jan 29 - Feb 1)&quot;">​</a></h3><ul><li><strong>Video:</strong> Record the &quot;Cinematic&quot; demo.</li><li><strong>Docs:</strong> Finalize <code>README.md</code> and submission forms.</li><li><strong>Submit:</strong> Win.</li></ul><hr><h2 id="️-contingency-plans" tabindex="-1">️ CONTINGENCY PLANS <a class="header-anchor" href="#️-contingency-plans" aria-label="Permalink to &quot;️ CONTINGENCY PLANS&quot;">​</a></h2><ul><li><strong>If Arcium fails:</strong> Fallback to standard SPL Token with a &quot;Mixer&quot; pattern (less cool, but functional).</li><li><strong>If Light Validator fails:</strong> Use <strong>Devnet</strong> exclusively. If Devnet is unstable, Mock the compression (store encrypted data in standard accounts) but keep the <em>interface</em> compatible.</li><li><strong>If Noir Verifier fails:</strong> Use a simple Merkle Proof verification in Rust (standard) instead of ZK-Circuit.</li></ul><hr><h2 id="-next-immediate-action" tabindex="-1"> NEXT IMMEDIATE ACTION <a class="header-anchor" href="#-next-immediate-action" aria-label="Permalink to &quot; NEXT IMMEDIATE ACTION&quot;">​</a></h2><p>Check <code>docs/plans/WORKTREE_A_PRIVACY.md</code> and <code>docs/plans/WORKTREE_B_LIGHT.md</code> for specific tasks.</p>',31)])])}const y=e(n,[["render",i]]);export{u as __pageData,y as default};
